export function zodiacSvg(sign: string): string | null {
  const key = (sign || '').trim().toUpperCase();
  const icon = ZODIAC_ICONS[key];
  if (!icon) return null;
  const paths = icon.paths.map((d) => `<path d="${d}" fill="currentColor"/>`).join("");
  return `<svg viewBox="0 0 ${icon.vw} ${icon.vh}" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" preserveAspectRatio="xMidYMid meet">${paths}</svg>`;
}